import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  Button,
  CircularProgress,
  Stack,
  Alert,
  Snackbar,
  LinearProgress,
  IconButton,
  useTheme,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow
} from '@mui/material';
import {
  Sync as SyncIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, startService, stopService, restartService, getRealtimeTraffic } from '../services/api';
import { motion } from 'framer-motion';
import { getCommonStyles } from '../styles/commonStyles';

const UPDATE_INTERVAL = 5000; // 5 seconds

const Dashboard = ({ mode, setMode, onDashboardClick }) => {
  const [systemInfo, setSystemInfo] = useState(null);
  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  // eslint-disable-next-line no-unused-vars
  const [realtimeTraffic, setRealtimeTraffic] = useState(null);

  const theme = useTheme();
  const styles = getCommonStyles(theme);

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const [info, status] = await Promise.all([
        getSystemInfo(),
        getSystemStatus()
      ]);
      setSystemInfo(info);
      setSubscriptions(status.subscriptions || []);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取仪表盘数据失败');
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchRealtimeTraffic = useCallback(async () => {
    try {
      const data = await getRealtimeTraffic();
      setRealtimeTraffic(data);
    } catch (err) {
      console.error('Failed to fetch realtime traffic:', err);
    }
  }, []);

  useEffect(() => {
    fetchDashboardData();
    const dashboardInterval = setInterval(fetchDashboardData, UPDATE_INTERVAL);
    const trafficInterval = setInterval(fetchRealtimeTraffic, 1000);
    return () => {
      clearInterval(dashboardInterval);
      clearInterval(trafficInterval);
    };
  }, [fetchDashboardData, fetchRealtimeTraffic]);

  const handleServiceAction = async (action, serviceName) => {
    try {
      setLoading(true);
      switch (action) {
        case 'start':
          await startService(serviceName);
          break;
        case 'stop':
          await stopService(serviceName);
          break;
        case 'restart':
          await restartService(serviceName);
          break;
        default:
          throw new Error('Invalid action');
      }
      setSuccess(true);
      await fetchDashboardData();
    } catch (err) {
      setError(err.response?.data?.error || '操作失败');
    } finally {
      setLoading(false);
    }
  };

  const formatUptime = (seconds) => {
    const days = Math.floor(seconds / (24 * 60 * 60));
    const hours = Math.floor((seconds % (24 * 60 * 60)) / (60 * 60));
    const minutes = Math.floor((seconds % (60 * 60)) / 60);

    let result = [];
    if (days > 0) result.push(`${days}天`);
    if (hours > 0) result.push(`${hours}小时`);
    if (minutes > 0) result.push(`${minutes}分钟`);

    return result.join(' ') || '刚刚启动';
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  if (!systemInfo && loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                仪表盘
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <Grid container spacing={1.5}>
          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card sx={styles.card}>
                <CardContent>
                  <Box sx={{ position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', p: 2 }}>
                    <CircularProgress
                      variant="determinate"
                      value={systemInfo?.cpuUsage || 0}
                      size={120}
                      thickness={4}
                      sx={{
                        color: 'primary.main',
                        opacity: 0.8,
                      }}
                    />
                    <Box
                      sx={{
                        position: 'absolute',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                      }}
                    >
                      <Typography variant="h4" component="div" sx={{ fontWeight: 500 }}>
                        {systemInfo?.cpuUsage || 0}%
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        CPU
                      </Typography>
                    </Box>
                  </Box>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card sx={styles.card}>
                <CardContent>
                  <Box sx={{ position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', p: 2 }}>
                    <CircularProgress
                      variant="determinate"
                      value={systemInfo ? (systemInfo.memoryUsed / systemInfo.memoryTotal) * 100 : 0}
                      size={120}
                      thickness={4}
                      sx={{
                        color: 'primary.main',
                        opacity: 0.8,
                      }}
                    />
                    <Box
                      sx={{
                        position: 'absolute',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                      }}
                    >
                      <Typography variant="h4" component="div" sx={{ fontWeight: 500 }}>
                        {systemInfo ? Math.round((systemInfo.memoryUsed / systemInfo.memoryTotal) * 100) : 0}%
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        内存
                      </Typography>
                    </Box>
                  </Box>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card sx={styles.card}>
                <CardContent>
                  <Stack spacing={1}>
                    <Typography variant="h6" gutterBottom>
                      系统信息
                    </Typography>
                    <Stack spacing={0.5}>
                      <Typography variant="body2" color="text.secondary">
                        操作系统: {systemInfo?.os}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        架构: {systemInfo?.arch}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        运行时间: {systemInfo ? formatUptime(systemInfo.uptime) : ''}
                      </Typography>
                    </Stack>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card sx={styles.card}>
                <CardContent>
                  <Stack spacing={1}>
                    <Typography variant="h6" gutterBottom>
                      服务状态
                    </Typography>
                    <Stack spacing={0.5}>
                      {Object.entries(systemInfo?.services || {}).map(([service, status]) => (
                        <Box key={service} sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                          <Box
                            sx={{
                              width: 8,
                              height: 8,
                              borderRadius: '50%',
                              bgcolor: status ? 'success.main' : 'error.main',
                            }}
                          />
                          <Typography variant="body2" color="text.secondary">
                            {service}
                          </Typography>
                        </Box>
                      ))}
                    </Stack>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          <Grid item xs={12}>
            <motion.div variants={cardVariants}>
              <Card sx={styles.card}>
                <CardContent>
                  <Stack spacing={2}>
                    <Typography variant="h6">
                      订阅信息
                    </Typography>
                    <TableContainer>
                      <Table size="small" sx={styles.tableContainer}>
                        <TableHead>
                          <TableRow>
                            <TableCell>名称</TableCell>
                            <TableCell align="right">已用流量</TableCell>
                            <TableCell align="right">总流量</TableCell>
                            <TableCell align="right">到期时间</TableCell>
                            <TableCell align="right">更新时间</TableCell>
                          </TableRow>
                        </TableHead>
                        <TableBody>
                          {subscriptions.map((subscription) => (
                            <TableRow key={subscription.id}>
                              <TableCell component="th" scope="row">
                                {subscription.name}
                              </TableCell>
                              <TableCell align="right">{formatBytes(subscription.usedTraffic)}</TableCell>
                              <TableCell align="right">{formatBytes(subscription.totalTraffic)}</TableCell>
                              <TableCell align="right">{subscription.expireTime}</TableCell>
                              <TableCell align="right">{subscription.updateTime}</TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </TableContainer>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>
        </Grid>
      </motion.div>
    </Box>
  );
};

export default Dashboard;
